    {"offset": {"line": 155, "column": 0}, "map": {"version":3,"sources":["file:///Users/guest1/Desktop/React/foodcatalog/components/restaurant-card.tsx"],"sourcesContent":["import Link from \"next/link\"\nimport { Card } from \"@/components/ui/card\"\nimport { Star, MapPin } from \"lucide-react\"\nimport { Timestamp } from \"firebase/firestore\"\nimport { Key } from \"readline\"\n\ninterface Restaurant {\n  id?: Key | number | null | undefined\n  name: string,\n  slug?: string,\n  city: string,\n  category?: string,\n  shortDescription?: string,\n  coverImage?: string\n  rating?: string\n  reviewsCount?: string\n  status?: string\n  firmId?: string\n  restaurantId?: string\n  delivery?: boolean\n  createdAt?: Timestamp\n}\n\ninterface RestaurantCardProps {\n  restaurant: Restaurant\n}\n\nexport function RestaurantCard({ restaurant }: RestaurantCardProps) {\n  return (\n    <Link href={`/restaurant/${restaurant.id}`}>\n      <Card className=\"h-full overflow-hidden hover:shadow-lg transition-shadow cursor-pointer\">\n        {/* Image */}\n        <div className=\"relative h-48 bg-muted overflow-hidden\">\n          <img\n            src={restaurant.coverImage || \"/placeholder.svg\"}\n            alt={restaurant.name}\n            className=\"w-full h-full object-cover hover:scale-105 transition-transform\"\n          />\n          <div className=\"absolute top-3 right-3 bg-primary text-primary-foreground px-3 py-1 rounded-full text-sm font-semibold\">\n            price range\n          </div>\n        </div>\n\n        {/* Content */}\n        <div className=\"p-4\">\n          {/* Name and Rating */}\n          <div className=\"mb-3\">\n            <h3 className=\"font-bold text-lg text-foreground mb-2 line-clamp-2\">{restaurant.name}</h3>\n            <div className=\"flex items-center gap-2 mb-2\">\n              <div className=\"flex items-center gap-1\">\n                <Star className=\"w-4 h-4 fill-primary text-primary\" />\n                <span className=\"font-semibold text-foreground\">{restaurant.rating}</span>\n              </div>\n              <span className=\"text-sm text-muted-foreground\">({restaurant.reviewsCount})</span>\n            </div>\n          </div>\n\n          {/* Cuisine Tags */}\n          <div className=\"flex flex-wrap gap-1 mb-3\">\n            {restaurant.category}\n          </div>\n\n          {/* Address */}\n          <div className=\"flex items-start gap-2 text-sm text-muted-foreground\">\n            <MapPin className=\"w-4 h-4 flex-shrink-0 mt-0.5\" />\n            <span className=\"line-clamp-2\">{restaurant.city}</span>\n          </div>\n        </div>\n      </Card>\n    </Link>\n  )\n}\n"],"names":[],"mappings":";;;;;AAAA;AACA;AACA;AAAA;;;;;AAyBO,SAAS,eAAe,EAAE,UAAU,EAAuB;IAChE,qBACE,6LAAC,0KAAI;QAAC,MAAM,CAAC,YAAY,EAAE,WAAW,EAAE,EAAE;kBACxC,cAAA,6LAAC,oIAAI;YAAC,WAAU;;8BAEd,6LAAC;oBAAI,WAAU;;sCACb,6LAAC;4BACC,KAAK,WAAW,UAAU,IAAI;4BAC9B,KAAK,WAAW,IAAI;4BACpB,WAAU;;;;;;sCAEZ,6LAAC;4BAAI,WAAU;sCAAyG;;;;;;;;;;;;8BAM1H,6LAAC;oBAAI,WAAU;;sCAEb,6LAAC;4BAAI,WAAU;;8CACb,6LAAC;oCAAG,WAAU;8CAAuD,WAAW,IAAI;;;;;;8CACpF,6LAAC;oCAAI,WAAU;;sDACb,6LAAC;4CAAI,WAAU;;8DACb,6LAAC,6MAAI;oDAAC,WAAU;;;;;;8DAChB,6LAAC;oDAAK,WAAU;8DAAiC,WAAW,MAAM;;;;;;;;;;;;sDAEpE,6LAAC;4CAAK,WAAU;;gDAAgC;gDAAE,WAAW,YAAY;gDAAC;;;;;;;;;;;;;;;;;;;sCAK9E,6LAAC;4BAAI,WAAU;sCACZ,WAAW,QAAQ;;;;;;sCAItB,6LAAC;4BAAI,WAAU;;8CACb,6LAAC,uNAAM;oCAAC,WAAU;;;;;;8CAClB,6LAAC;oCAAK,WAAU;8CAAgB,WAAW,IAAI;;;;;;;;;;;;;;;;;;;;;;;;;;;;;AAM3D;KA5CgB"}},
    {"offset": {"line": 325, "column": 0}, "map": {"version":3,"sources":["file:///Users/guest1/Desktop/React/foodcatalog/app/discover/page.tsx"],"sourcesContent":["\"use client\"\n\nimport { useEffect, useState } from \"react\"\nimport { Input } from \"@/components/ui/input\"\nimport { Card } from \"@/components/ui/card\"\nimport { Search } from \"lucide-react\"\nimport { RestaurantCard } from \"@/components/restaurant-card\"\nimport { collection, getDocs, query, where, Timestamp } from \"firebase/firestore\"\nimport { useTranslation } from \"react-i18next\"\n\n\n//Types\nimport { PublicRestaurant } from \"../../data/types/publicRestaurant\"\nimport { db } from \"@/lib/firebase/client\"\n\n\nexport default function DiscoverPage() {\n\n  const [loading, setLoading] = useState(false)\n  const [resteurants, setResteurants] = useState<PublicRestaurant[]>([])\n\n  const { t } = useTranslation()\n  const [searchQuery, setSearchQuery] = useState(\"\")\n  //const [selectedCategory, setSelectedCategory] = useState(\"All\")\n  //const [selectedPrice, setSelectedPrice] = useState(\"All\")\n  //const [showFilters, setShowFilters] = useState(false)\n\n  const fetchRestaurants = async () => {\n    try {\n      const q = query(\n        collection(db, \"public_restaurants\"),\n        where(\"status\", \"==\", \"active\")\n      )\n\n      const snapshot = await getDocs(q)\n      const data = snapshot.docs.map((doc) => ({\n        id: doc.id,\n        ...(doc.data() as Omit<PublicRestaurant, \"id\">),\n      }))\n\n      setResteurants(data as unknown as PublicRestaurant[])\n    }\n\n    catch (error) {\n      console.error(\"Error fetching restaurants:\", error)\n    } finally {\n      setLoading(false)\n    }\n  }\n\n  useEffect(() => {\n    fetchRestaurants()\n    setLoading(true)\n  }, [])\n  // Close filters on window resize if desktop\n\n  // Filter restaurants based on search and filters\n\n  if (loading) {\n    return (\n      <main className=\"min-h-screen flex items-center justify-center bg-background\">\n        <p className=\"text-foreground text-sm sm:text-base\">Loading restaurants...</p>\n      </main>\n    )\n  }\n  return (\n    <main className=\"min-h-screen bg-background\">\n      <div className=\"max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8 sm:py-8\">\n        {/* Header */}\n        <div className=\"mb-6 sm:mb-8\">\n          <h1 className=\"text-2xl sm:text-3xl lg:text-4xl font-bold text-foreground mb-2\">{t(\"discover_page_header\")}</h1>\n          <p className=\"text-sm sm:text-base text-muted-foreground\">\n            {t(\"discover_page_subheader\")}\n          </p>\n        </div>\n\n        {/* Search Bar */}\n        <div className=\"mb-6 sm:mb-8\">\n          <div className=\"relative\">\n            <Search className=\"absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground\" />\n            <Input\n              placeholder={t(\"discover_page_add_restaurant_search\")}\n              className=\"pl-10 h-12 text-base\"\n              value={searchQuery}\n              onChange={(e) => setSearchQuery(e.target.value)}\n            />\n          </div>\n        </div>\n\n        {/* Filters - Mobile Toggle and Desktop Always Visible */}\n        <div className=\"mb-6\">\n\n        </div>\n\n        {/* Results Info */}\n        <div className=\"mb-6\">\n          <p className=\"text-xs sm:text-sm text-muted-foreground\">\n\n          </p>\n        </div>\n\n        {/* Restaurant Grid - Mobile: 1 column, Tablet: 2 columns, Desktop: 3 columns */}\n        <div className=\"grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6\">\n          {resteurants.map((restaurant) => (\n            <RestaurantCard restaurant={{ ...restaurant, createdAt: Timestamp.fromMillis(restaurant.createdAt) }} />\n          ))}\n        </div>\n      </div>\n      {resteurants.length === 0 ? <Card className=\"p-8 sm:p-12 text-center\">\n        <p className=\"text-sm sm:text-base text-muted-foreground mb-2\">No restaurants found</p>\n        <p className=\"text-xs sm:text-sm text-muted-foreground\">Try adjusting your search or filters</p>\n      </Card> : null}\n\n\n\n    </main >)\n\n}\n"],"names":[],"mappings":";;;;;AAEA;AACA;AACA;AACA;AACA;AACA;AAAA;AACA;AAAA;AAKA;;;AAbA;;;;;;;;;AAgBe,SAAS;;IAEtB,MAAM,CAAC,SAAS,WAAW,GAAG,IAAA,yKAAQ,EAAC;IACvC,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,yKAAQ,EAAqB,EAAE;IAErE,MAAM,EAAE,CAAC,EAAE,GAAG,IAAA,qLAAc;IAC5B,MAAM,CAAC,aAAa,eAAe,GAAG,IAAA,yKAAQ,EAAC;IAC/C,iEAAiE;IACjE,2DAA2D;IAC3D,uDAAuD;IAEvD,MAAM,mBAAmB;QACvB,IAAI;YACF,MAAM,IAAI,IAAA,2KAAK,EACb,IAAA,gLAAU,EAAC,kIAAE,EAAE,uBACf,IAAA,2KAAK,EAAC,UAAU,MAAM;YAGxB,MAAM,WAAW,MAAM,IAAA,6KAAO,EAAC;YAC/B,MAAM,OAAO,SAAS,IAAI,CAAC,GAAG,CAAC,CAAC,MAAQ,CAAC;oBACvC,IAAI,IAAI,EAAE;oBACV,GAAI,IAAI,IAAI,EAAE;gBAChB,CAAC;YAED,eAAe;QACjB,EAEA,OAAO,OAAO;YACZ,QAAQ,KAAK,CAAC,+BAA+B;QAC/C,SAAU;YACR,WAAW;QACb;IACF;IAEA,IAAA,0KAAS;kCAAC;YACR;YACA,WAAW;QACb;iCAAG,EAAE;IACL,4CAA4C;IAE5C,iDAAiD;IAEjD,IAAI,SAAS;QACX,qBACE,6LAAC;YAAK,WAAU;sBACd,cAAA,6LAAC;gBAAE,WAAU;0BAAuC;;;;;;;;;;;IAG1D;IACA,qBACE,6LAAC;QAAK,WAAU;;0BACd,6LAAC;gBAAI,WAAU;;kCAEb,6LAAC;wBAAI,WAAU;;0CACb,6LAAC;gCAAG,WAAU;0CAAmE,EAAE;;;;;;0CACnF,6LAAC;gCAAE,WAAU;0CACV,EAAE;;;;;;;;;;;;kCAKP,6LAAC;wBAAI,WAAU;kCACb,cAAA,6LAAC;4BAAI,WAAU;;8CACb,6LAAC,mNAAM;oCAAC,WAAU;;;;;;8CAClB,6LAAC,sIAAK;oCACJ,aAAa,EAAE;oCACf,WAAU;oCACV,OAAO;oCACP,UAAU,CAAC,IAAM,eAAe,EAAE,MAAM,CAAC,KAAK;;;;;;;;;;;;;;;;;kCAMpD,6LAAC;wBAAI,WAAU;;;;;;kCAKf,6LAAC;wBAAI,WAAU;kCACb,cAAA,6LAAC;4BAAE,WAAU;;;;;;;;;;;kCAMf,6LAAC;wBAAI,WAAU;kCACZ,YAAY,GAAG,CAAC,CAAC,2BAChB,6LAAC,sJAAc;gCAAC,YAAY;oCAAE,GAAG,UAAU;oCAAE,WAAW,+KAAS,CAAC,UAAU,CAAC,WAAW,SAAS;gCAAE;;;;;;;;;;;;;;;;;YAIxG,YAAY,MAAM,KAAK,kBAAI,6LAAC,oIAAI;gBAAC,WAAU;;kCAC1C,6LAAC;wBAAE,WAAU;kCAAkD;;;;;;kCAC/D,6LAAC;wBAAE,WAAU;kCAA2C;;;;;;;;;;;uBAChD;;;;;;;AAMhB;GArGwB;;QAKR,qLAAc;;;KALN"}},
