    {"offset": {"line": 155, "column": 0}, "map": {"version":3,"sources":["file:///Users/guest1/Desktop/React/foodcatalog/components/restaurant-card.tsx"],"sourcesContent":["import Link from \"next/link\"\nimport { Card } from \"@/components/ui/card\"\nimport { Star, MapPin } from \"lucide-react\"\n\ninterface Restaurant {\n  id: number\n  name: string\n  category: string\n  rating: number\n  reviewCount: number\n  image: string\n  address: string\n  cuisine: string[]\n  priceRange: string\n}\n\ninterface RestaurantCardProps {\n  restaurant: Restaurant\n}\n\nexport function RestaurantCard({ restaurant }: RestaurantCardProps) {\n  return (\n    <Link href={`/restaurant/${restaurant.id}`}>\n      <Card className=\"h-full overflow-hidden hover:shadow-lg transition-shadow cursor-pointer\">\n        {/* Image */}\n        <div className=\"relative h-48 bg-muted overflow-hidden\">\n          <img\n            src={restaurant.image || \"/placeholder.svg\"}\n            alt={restaurant.name}\n            className=\"w-full h-full object-cover hover:scale-105 transition-transform\"\n          />\n          <div className=\"absolute top-3 right-3 bg-primary text-primary-foreground px-3 py-1 rounded-full text-sm font-semibold\">\n            {restaurant.priceRange}\n          </div>\n        </div>\n\n        {/* Content */}\n        <div className=\"p-4\">\n          {/* Name and Rating */}\n          <div className=\"mb-3\">\n            <h3 className=\"font-bold text-lg text-foreground mb-2 line-clamp-2\">{restaurant.name}</h3>\n            <div className=\"flex items-center gap-2 mb-2\">\n              <div className=\"flex items-center gap-1\">\n                <Star className=\"w-4 h-4 fill-primary text-primary\" />\n                <span className=\"font-semibold text-foreground\">{restaurant.rating}</span>\n              </div>\n              <span className=\"text-sm text-muted-foreground\">({restaurant.reviewCount})</span>\n            </div>\n          </div>\n\n          {/* Cuisine Tags */}\n          <div className=\"flex flex-wrap gap-1 mb-3\">\n            {restaurant.cuisine.slice(0, 2).map((cuisine) => (\n              <span key={cuisine} className=\"text-xs bg-muted text-muted-foreground px-2 py-1 rounded\">\n                {cuisine}\n              </span>\n            ))}\n          </div>\n\n          {/* Address */}\n          <div className=\"flex items-start gap-2 text-sm text-muted-foreground\">\n            <MapPin className=\"w-4 h-4 flex-shrink-0 mt-0.5\" />\n            <span className=\"line-clamp-2\">{restaurant.address}</span>\n          </div>\n        </div>\n      </Card>\n    </Link>\n  )\n}\n"],"names":[],"mappings":";;;;;AAAA;AACA;AACA;AAAA;;;;;AAkBO,SAAS,eAAe,EAAE,UAAU,EAAuB;IAChE,qBACE,6LAAC,0KAAI;QAAC,MAAM,CAAC,YAAY,EAAE,WAAW,EAAE,EAAE;kBACxC,cAAA,6LAAC,oIAAI;YAAC,WAAU;;8BAEd,6LAAC;oBAAI,WAAU;;sCACb,6LAAC;4BACC,KAAK,WAAW,KAAK,IAAI;4BACzB,KAAK,WAAW,IAAI;4BACpB,WAAU;;;;;;sCAEZ,6LAAC;4BAAI,WAAU;sCACZ,WAAW,UAAU;;;;;;;;;;;;8BAK1B,6LAAC;oBAAI,WAAU;;sCAEb,6LAAC;4BAAI,WAAU;;8CACb,6LAAC;oCAAG,WAAU;8CAAuD,WAAW,IAAI;;;;;;8CACpF,6LAAC;oCAAI,WAAU;;sDACb,6LAAC;4CAAI,WAAU;;8DACb,6LAAC,6MAAI;oDAAC,WAAU;;;;;;8DAChB,6LAAC;oDAAK,WAAU;8DAAiC,WAAW,MAAM;;;;;;;;;;;;sDAEpE,6LAAC;4CAAK,WAAU;;gDAAgC;gDAAE,WAAW,WAAW;gDAAC;;;;;;;;;;;;;;;;;;;sCAK7E,6LAAC;4BAAI,WAAU;sCACZ,WAAW,OAAO,CAAC,KAAK,CAAC,GAAG,GAAG,GAAG,CAAC,CAAC,wBACnC,6LAAC;oCAAmB,WAAU;8CAC3B;mCADQ;;;;;;;;;;sCAOf,6LAAC;4BAAI,WAAU;;8CACb,6LAAC,uNAAM;oCAAC,WAAU;;;;;;8CAClB,6LAAC;oCAAK,WAAU;8CAAgB,WAAW,OAAO;;;;;;;;;;;;;;;;;;;;;;;;;;;;;AAM9D;KAhDgB"}},
    {"offset": {"line": 332, "column": 0}, "map": {"version":3,"sources":["file:///Users/guest1/Desktop/React/foodcatalog/app/discover/page.tsx"],"sourcesContent":["\"use client\"\n\nimport { useState } from \"react\"\nimport { Button } from \"@/components/ui/button\"\nimport { Input } from \"@/components/ui/input\"\nimport { Card } from \"@/components/ui/card\"\nimport { Search } from \"lucide-react\"\nimport { RestaurantCard } from \"@/components/restaurant-card\"\n\n// Mock data for MVP\nconst MOCK_RESTAURANTS = [\n  {\n    id: 1,\n    name: \"La Familia Trattoria\",\n    category: \"Italian\",\n    rating: 4.8,\n    reviewCount: 245,\n    image: \"/italian-restaurant-interior.jpg\",\n    address: \"ul. Główna 12, Kraków\",\n    cuisine: [\"Italian\", \"Pasta\", \"Pizza\"],\n    priceRange: \"$$\",\n  },\n  {\n    id: 2,\n    name: \"Sushi & More\",\n    category: \"Japanese\",\n    rating: 4.6,\n    reviewCount: 189,\n    image: \"/japanese-sushi-restaurant.png\",\n    address: \"Rynek 5, Kraków\",\n    cuisine: [\"Japanese\", \"Sushi\", \"Asian\"],\n    priceRange: \"$$$\",\n  },\n  {\n    id: 3,\n    name: \"Grill House\",\n    category: \"Steakhouse\",\n    rating: 4.7,\n    reviewCount: 312,\n    image: \"/steakhouse-interior.jpg\",\n    address: \"ul. Szeroka 8, Kraków\",\n    cuisine: [\"Grill\", \"Steak\", \"Meat\"],\n    priceRange: \"$$$\",\n  },\n  {\n    id: 4,\n    name: \"Cafe Botanica\",\n    category: \"Cafe\",\n    rating: 4.5,\n    reviewCount: 428,\n    image: \"/cozy-cafe-with-plants.jpg\",\n    address: \"ul. Krakowska 3, Kraków\",\n    cuisine: [\"Cafe\", \"Brunch\", \"Coffee\"],\n    priceRange: \"$\",\n  },\n  {\n    id: 5,\n    name: \"El Mariachi\",\n    category: \"Mexican\",\n    rating: 4.4,\n    reviewCount: 156,\n    image: \"/mexican-restaurant-colorful.jpg\",\n    address: \"Plac Nowy 15, Kraków\",\n    cuisine: [\"Mexican\", \"Tacos\", \"Latin\"],\n    priceRange: \"$$\",\n  },\n  {\n    id: 6,\n    name: \"The Greek Tavern\",\n    category: \"Greek\",\n    rating: 4.7,\n    reviewCount: 203,\n    image: \"/greek-mediterranean-tavern.jpg\",\n    address: \"ul. Grecka 20, Kraków\",\n    cuisine: [\"Greek\", \"Mediterranean\", \"Seafood\"],\n    priceRange: \"$$\",\n  },\n]\n\nconst CATEGORIES = [\"All\", \"Italian\", \"Japanese\", \"Steakhouse\", \"Cafe\", \"Mexican\", \"Greek\"]\nconst PRICE_RANGES = [\"All\", \"$\", \"$$\", \"$$$\"]\n\nexport default function DiscoverPage() {\n  const [searchQuery, setSearchQuery] = useState(\"\")\n  const [selectedCategory, setSelectedCategory] = useState(\"All\")\n  const [selectedPrice, setSelectedPrice] = useState(\"All\")\n  const [showFilters, setShowFilters] = useState(false)\n\n  // Filter restaurants based on search and filters\n  const filteredRestaurants = MOCK_RESTAURANTS.filter((restaurant) => {\n    const matchesSearch =\n      restaurant.name.toLowerCase().includes(searchQuery.toLowerCase()) ||\n      restaurant.address.toLowerCase().includes(searchQuery.toLowerCase()) ||\n      restaurant.cuisine.some((c) => c.toLowerCase().includes(searchQuery.toLowerCase()))\n\n    const matchesCategory = selectedCategory === \"All\" || restaurant.category === selectedCategory\n    const matchesPrice = selectedPrice === \"All\" || restaurant.priceRange === selectedPrice\n\n    return matchesSearch && matchesCategory && matchesPrice\n  })\n\n  return (\n    <main className=\"min-h-screen bg-background\">\n      <div className=\"max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8 sm:py-8\">\n        {/* Header */}\n        <div className=\"mb-6 sm:mb-8\">\n          <h1 className=\"text-2xl sm:text-3xl lg:text-4xl font-bold text-foreground mb-2\">Discover Restaurants</h1>\n          <p className=\"text-sm sm:text-base text-muted-foreground\">\n            Find and explore amazing dining experiences near you\n          </p>\n        </div>\n\n        {/* Search Bar */}\n        <div className=\"mb-6 sm:mb-8\">\n          <div className=\"relative\">\n            <Search className=\"absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground\" />\n            <Input\n              placeholder=\"Search restaurants, cuisine...\"\n              className=\"pl-10 h-12 text-base\"\n              value={searchQuery}\n              onChange={(e) => setSearchQuery(e.target.value)}\n            />\n          </div>\n        </div>\n\n        {/* Filters - Mobile Toggle and Desktop Always Visible */}\n        <div className=\"mb-6\">\n          <button\n            onClick={() => setShowFilters(!showFilters)}\n            className=\"md:hidden w-full mb-4 px-4 py-3 bg-muted text-foreground font-medium rounded-lg flex items-center justify-between\"\n          >\n            <span>Filters</span>\n            <span className={`transition-transform ${showFilters ? \"rotate-180\" : \"\"}`}>▼</span>\n          </button>\n\n          <div className={`grid gap-4 mb-6 ${showFilters ? \"block\" : \"hidden\"} md:block`}>\n            {/* Category Filter */}\n            <div>\n              <h3 className=\"text-sm font-semibold text-foreground mb-3\">Category</h3>\n              <div className=\"flex flex-wrap gap-2\">\n                {CATEGORIES.map((category) => (\n                  <Button\n                    key={category}\n                    variant={selectedCategory === category ? \"default\" : \"outline\"}\n                    size=\"sm\"\n                    onClick={() => {\n                      setSelectedCategory(category)\n                      setShowFilters(false)\n                    }}\n                    className=\"text-xs sm:text-sm\"\n                  >\n                    {category}\n                  </Button>\n                ))}\n              </div>\n            </div>\n\n            {/* Price Range Filter */}\n            <div>\n              <h3 className=\"text-sm font-semibold text-foreground mb-3\">Price Range</h3>\n              <div className=\"flex flex-wrap gap-2\">\n                {PRICE_RANGES.map((price) => (\n                  <Button\n                    key={price}\n                    variant={selectedPrice === price ? \"default\" : \"outline\"}\n                    size=\"sm\"\n                    onClick={() => {\n                      setSelectedPrice(price)\n                      setShowFilters(false)\n                    }}\n                    className=\"text-xs sm:text-sm\"\n                  >\n                    {price === \"All\" ? \"All\" : price}\n                  </Button>\n                ))}\n              </div>\n            </div>\n          </div>\n        </div>\n\n        {/* Results Info */}\n        <div className=\"mb-6\">\n          <p className=\"text-xs sm:text-sm text-muted-foreground\">\n            Showing {filteredRestaurants.length} restaurant{filteredRestaurants.length !== 1 ? \"s\" : \"\"}\n          </p>\n        </div>\n\n        {/* Restaurant Grid - Mobile: 1 column, Tablet: 2 columns, Desktop: 3 columns */}\n        {filteredRestaurants.length > 0 ? (\n          <div className=\"grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6\">\n            {filteredRestaurants.map((restaurant) => (\n              <RestaurantCard key={restaurant.id} restaurant={restaurant} />\n            ))}\n          </div>\n        ) : (\n          <Card className=\"p-8 sm:p-12 text-center\">\n            <p className=\"text-sm sm:text-base text-muted-foreground mb-2\">No restaurants found</p>\n            <p className=\"text-xs sm:text-sm text-muted-foreground\">Try adjusting your search or filters</p>\n          </Card>\n        )}\n      </div>\n    </main>\n  )\n}\n"],"names":[],"mappings":";;;;;AAEA;AACA;AACA;AACA;AACA;AACA;;;AAPA;;;;;;;AASA,oBAAoB;AACpB,MAAM,mBAAmB;IACvB;QACE,IAAI;QACJ,MAAM;QACN,UAAU;QACV,QAAQ;QACR,aAAa;QACb,OAAO;QACP,SAAS;QACT,SAAS;YAAC;YAAW;YAAS;SAAQ;QACtC,YAAY;IACd;IACA;QACE,IAAI;QACJ,MAAM;QACN,UAAU;QACV,QAAQ;QACR,aAAa;QACb,OAAO;QACP,SAAS;QACT,SAAS;YAAC;YAAY;YAAS;SAAQ;QACvC,YAAY;IACd;IACA;QACE,IAAI;